from dataclasses import dataclass

@dataclass
class FrictionItem:
    id: str
    title: str
    area: str
    mention_count: int     # times seen across all signal channels
    affected_teams: int    # distinct teams reporting this
    severity_avg: float    # 1-3 average across reports
    ttfd_impact_days: float  # estimated days added to TTFD if unresolved
    effort_days: float     # engineering days to fix

    @property
    def reach(self) -> float:
        return self.affected_teams

    @property
    def impact(self) -> float:
        # Normalised: severity + TTFD impact (capped at 10)
        return min(10.0, self.severity_avg * 2 + self.ttfd_impact_days)

    @property
    def priority_score(self) -> float:
        if self.effort_days == 0:
            return 0.0
        return round((self.reach * self.impact) / self.effort_days, 2)

    @property
    def priority_tier(self) -> str:
        s = self.priority_score
        if s >= 20:   return "P0 — this sprint"
        if s >= 10:   return "P1 — next sprint"
        if s >= 3:    return "P2 — backlog"
        return "P3 — won't fix"

# Example scoring session
items = [
    FrictionItem("F-101", "Read-only key gives cryptic 403", "auth",
                 mention_count=9, affected_teams=6, severity_avg=2.4,
                 ttfd_impact_days=2.0, effort_days=0.5),
    FrictionItem("F-87", "No streaming example in SDK docs", "sdk-docs",
                 mention_count=5, affected_teams=4, severity_avg=1.8,
                 ttfd_impact_days=0.5, effort_days=1.0),
    FrictionItem("F-94", "eval-runner requires Python 3.11+", "eval-runner",
                 mention_count=3, affected_teams=2, severity_avg=2.0,
                 ttfd_impact_days=0.5, effort_days=5.0),
]

for item in sorted(items, key=lambda x: -x.priority_score):
    print(f"{item.id} ({item.area}): score={item.priority_score} → {item.priority_tier}")

# Output:
# F-101 (auth): score=76.8 → P0 — this sprint
# F-87 (sdk-docs): score=18.0 → P1 — next sprint
# F-94 (eval-runner): score=2.4 → P3 — won't fix
